namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0
        ? Math.Round((double)RatingSum / TotalRatings, 1)
        : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes = CreateSeedData();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public IReadOnlyList<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().Order().ToList();
        }
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes
                .Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase))
                .ToList();
        }
    }

    public Recipe? GetById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars is < 1 or > 5) return;

        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is null) return;
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        lock (_lock)
        {
            var recipe = new Recipe
            {
                Id = _nextId++,
                Title = submission.Title.Trim(),
                Category = submission.Category.Trim(),
                Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
                Ingredients = submission.Ingredients
                    .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .ToList(),
                Steps = submission.Steps
                    .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                    .ToList()
            };
            _recipes.Add(recipe);
            return recipe;
        }
    }

    private static List<Recipe> CreateSeedData() =>
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple, classic pizza with fresh mozzarella, tomatoes, and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = [
                "Preheat oven to 475°F (245°C) with a pizza stone.",
                "Stretch dough into a 12-inch round.",
                "Spread crushed tomatoes over the dough.",
                "Tear mozzarella and distribute evenly.",
                "Bake 10-12 minutes until crust is golden.",
                "Top with fresh basil and a drizzle of olive oil."
            ],
            TotalRatings = 24, RatingSum = 108
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta made with eggs, cheese, pancetta, and pepper.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = [
                "Cook spaghetti in salted boiling water until al dente.",
                "Fry pancetta until crispy.",
                "Whisk eggs with grated pecorino and black pepper.",
                "Toss hot pasta with pancetta, then quickly stir in egg mixture.",
                "Serve immediately with extra cheese and pepper."
            ],
            TotalRatings = 18, RatingSum = 85
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = [
                "Marinate chicken in yogurt and spices for at least 1 hour.",
                "Grill or broil chicken until lightly charred.",
                "Sauté onion, garlic, and ginger. Add tomato sauce and spices.",
                "Simmer sauce 15 minutes, then stir in cream.",
                "Add chicken pieces and simmer 10 more minutes.",
                "Serve with basmati rice or naan bread."
            ],
            TotalRatings = 31, RatingSum = 147
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Description = "A vibrant stir-fried noodle dish with vegetables and tangy sauce.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Scallions", "Eggs"],
            Steps = [
                "Soak rice noodles in warm water until pliable.",
                "Mix tamarind paste, fish sauce, sugar, and lime juice for the sauce.",
                "Stir-fry tofu until golden, set aside.",
                "Scramble eggs in the wok, then add noodles and sauce.",
                "Toss with bean sprouts, tofu, and scallions.",
                "Serve topped with crushed peanuts and lime wedges."
            ],
            TotalRatings = 15, RatingSum = 66
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef tacos with fresh toppings.",
            Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
            Steps = [
                "Brown ground beef and drain excess fat.",
                "Add taco seasoning and water, simmer 5 minutes.",
                "Warm taco shells in the oven.",
                "Fill shells with beef and top with lettuce, tomato, cheese, and sour cream."
            ],
            TotalRatings = 22, RatingSum = 92
        },
        new()
        {
            Id = 6, Title = "Miso Ramen", Category = "Japanese",
            Description = "A warming bowl of miso-flavored ramen with rich toppings.",
            Ingredients = ["Ramen noodles", "Miso paste", "Chicken broth", "Soy sauce", "Soft-boiled egg", "Nori", "Scallions", "Chashu pork"],
            Steps = [
                "Simmer chicken broth with miso paste and soy sauce.",
                "Cook ramen noodles according to package directions.",
                "Prepare soft-boiled eggs (6.5 minutes).",
                "Slice chashu pork thinly.",
                "Assemble bowls: noodles, then broth, topped with egg, pork, nori, and scallions."
            ],
            TotalRatings = 19, RatingSum = 90
        },
        new()
        {
            Id = 7, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh and zesty avocado dip, perfect with tortilla chips.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt", "Tomato"],
            Steps = [
                "Halve avocados and remove pits.",
                "Mash avocados to desired consistency.",
                "Stir in diced onion, tomato, jalapeño, and cilantro.",
                "Add lime juice and salt to taste.",
                "Serve immediately with tortilla chips."
            ],
            TotalRatings = 27, RatingSum = 121
        },
        new()
        {
            Id = 8, Title = "Tom Yum Soup", Category = "Thai",
            Description = "A hot and sour Thai soup with shrimp and mushrooms.",
            Ingredients = ["Shrimp", "Mushrooms", "Lemongrass", "Galangal", "Kaffir lime leaves", "Fish sauce", "Lime juice", "Chili paste"],
            Steps = [
                "Bring water to a boil with lemongrass, galangal, and lime leaves.",
                "Add mushrooms and simmer 5 minutes.",
                "Add shrimp and cook until pink.",
                "Stir in fish sauce, lime juice, and chili paste.",
                "Serve hot, garnished with cilantro."
            ],
            TotalRatings = 14, RatingSum = 63
        }
    ];
}

