﻿@page "/"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>RecipeHub — Home</PageTitle>

<section class="hero">
    <h1>Welcome to RecipeHub</h1>
    <p>Discover and share delicious recipes from around the world.</p>
</section>

<section class="categories-section">
    <h2>Browse by Category</h2>
    <div class="category-grid">
        @foreach (var category in RecipeService.GetCategories())
        {
            <a href="/category/@Uri.EscapeDataString(category)" class="category-card">
                <span class="category-icon">@GetCategoryIcon(category)</span>
                <span class="category-name">@category</span>
                <span class="category-count">@RecipeService.GetByCategory(category).Count recipes</span>
            </a>
        }
    </div>
</section>

@code {
    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🍜",
        "Mexican" => "🌮",
        "Japanese" => "🍱",
        _ => "🍽️"
    };
}

