@page "/recipe/{Id:int}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@(_recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

<nav class="breadcrumb">
    <a href="/">Home</a>
    @if (_recipe is not null)
    {
        @: &rsaquo; <a href="/category/@Uri.EscapeDataString(_recipe.Category)">@_recipe.Category</a>
    }
    &rsaquo; <span>Recipe</span>
</nav>

@if (_recipe is null)
{
    <h1>Recipe not found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <article class="recipe-detail">
        <h1>@_recipe.Title</h1>
        <p class="recipe-description">@_recipe.Description</p>

        <RecipeHub.Components.Shared.StarRating RecipeId="@_recipe.Id" @rendermode="InteractiveServer" />

        <section class="recipe-section">
            <h2>Ingredients</h2>
            <ul class="ingredients-list">
                @foreach (var ingredient in _recipe.Ingredients)
                {
                    <li>@ingredient</li>
                }
            </ul>
        </section>

        <section class="recipe-section">
            <h2>Steps</h2>
            <ol class="steps-list">
                @foreach (var step in _recipe.Steps)
                {
                    <li>@step</li>
                }
            </ol>
        </section>
    </article>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@using RecipeHub.Models
@using RecipeHub.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav class="breadcrumb">
    <a href="/">Home</a> &rsaquo; <span>Submit Recipe</span>
</nav>

<h1>Submit a Recipe</h1>

@if (_submitted)
{
    <div class="success-message">
        <h2>🎉 Recipe submitted!</h2>
        <p>Your recipe "<strong>@_submission.Title</strong>" has been added.</p>
        <a href="/recipe/@_createdId" class="btn">View Recipe</a>
    </div>
}
else
{
    <EditForm Model="_submission" OnValidSubmit="HandleSubmit" class="submit-form" FormName="recipeForm">
        <div class="form-group">
            <label for="title">Recipe Title</label>
            <InputText id="title" @bind-Value="_submission.Title" placeholder="e.g., Grandma's Apple Pie" required />
        </div>

        <div class="form-group">
            <label for="category">Category</label>
            <InputSelect id="category" @bind-Value="_submission.Category" required>
                <option value="">— Select a category —</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="form-group">
            <label for="ingredients">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="_submission.Ingredients" rows="6"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" required />
        </div>

        <div class="form-group">
            <label for="steps">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="_submission.Steps" rows="6"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." required />
        </div>

        <button type="submit" class="btn btn-primary"
                disabled="@(string.IsNullOrWhiteSpace(_submission.Title) || string.IsNullOrWhiteSpace(_submission.Category))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private RecipeSubmission _submission = new();
    private bool _submitted;
    private int _createdId;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title) || string.IsNullOrWhiteSpace(_submission.Category))
            return;

        var recipe = RecipeService.AddRecipe(_submission);
        _createdId = recipe.Id;
        _submitted = true;
    }
}

@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="star-rating">
    <span class="rating-label">Rate this recipe:</span>
    <span class="stars-interactive">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="star-btn @(star <= (_hovered > 0 ? _hovered : _selected) ? "filled" : "")"
                    @onclick="() => SelectStar(star)"
                    @onmouseover="() => _hovered = star"
                    @onmouseout="() => _hovered = 0"
                    aria-label="Rate @star stars">
                @(star <= (_hovered > 0 ? _hovered : _selected) ? "★" : "☆")
            </button>
        }
    </span>
    @if (_selected > 0)
    {
        <span class="rating-confirmation">You rated @_selected star@(_selected > 1 ? "s" : ""). Thanks!</span>
    }
    <span class="rating-average">Average: @_average / 5 (@_totalRatings ratings)</span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int _selected;
    private int _hovered;
    private double _average;
    private int _totalRatings;

    protected override void OnParametersSet()
    {
        RefreshRating();
    }

    private void SelectStar(int stars)
    {
        _selected = stars;
        RecipeService.AddRating(RecipeId, stars);
        RefreshRating();
    }

    private void RefreshRating()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            _average = recipe.AverageRating;
            _totalRatings = recipe.TotalRatings;
        }
    }
}

