toolArgs.new_str:
/* === Reset & Base === */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
    --color-primary: #e05d26;
    --color-primary-dark: #c04a1a;
    --color-bg: #faf8f5;
    --color-card: #ffffff;
    --color-text: #2d2d2d;
    --color-muted: #6b6b6b;
    --color-border: #e8e4e0;
    --color-star: #f0a500;
    --color-success: #2e7d32;
    --radius: 10px;
    --shadow: 0 2px 8px rgba(0,0,0,0.08);
}

html { font-family: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif; }
body { background: var(--color-bg); color: var(--color-text); line-height: 1.6; }
a { color: var(--color-primary); text-decoration: none; }
a:hover { text-decoration: underline; }

.container { max-width: 960px; margin: 0 auto; padding: 0 1.5rem; }

/* === Header === */
.site-header {
    background: var(--color-card);
    border-bottom: 2px solid var(--color-border);
    padding: 1rem 0;
}
.header-content { display: flex; align-items: center; justify-content: space-between; }
.logo { font-size: 1.5rem; font-weight: 700; color: var(--color-primary); }
.logo:hover { text-decoration: none; }
.site-header nav { display: flex; gap: 1.5rem; }
.site-header nav a { color: var(--color-text); font-weight: 500; }
.site-header nav a:hover { color: var(--color-primary); text-decoration: none; }

/* === Footer === */
.site-footer { text-align: center; padding: 2rem 0; margin-top: 3rem; color: var(--color-muted); font-size: 0.9rem; border-top: 1px solid var(--color-border); }

/* === Page layout === */
.page { min-height: 100vh; display: flex; flex-direction: column; }
.page > main { flex: 1; padding: 2rem 0; }

/* === Hero === */
.hero { text-align: center; padding: 3rem 0 2rem; }
.hero h1 { font-size: 2.4rem; margin-bottom: 0.5rem; }
.hero p { font-size: 1.15rem; color: var(--color-muted); }

/* === Category grid === */
.categories-section h2 { margin-bottom: 1rem; }
.category-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 1rem; }
.category-card {
    display: flex; flex-direction: column; align-items: center; gap: 0.3rem;
    background: var(--color-card); border: 1px solid var(--color-border);
    border-radius: var(--radius); padding: 1.5rem 1rem;
    transition: box-shadow 0.2s, transform 0.2s; text-align: center; color: var(--color-text);
}
.category-card:hover { box-shadow: var(--shadow); transform: translateY(-2px); text-decoration: none; }
.category-icon { font-size: 2.5rem; }
.category-name { font-weight: 600; font-size: 1.1rem; }
.category-count { font-size: 0.85rem; color: var(--color-muted); }

/* === Recipe grid === */
.recipe-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 1.25rem; }
.recipe-card {
    background: var(--color-card); border: 1px solid var(--color-border);
    border-radius: var(--radius); padding: 1.25rem;
    transition: box-shadow 0.2s; color: var(--color-text);
}
.recipe-card:hover { box-shadow: var(--shadow); text-decoration: none; }
.recipe-card h3 { margin-bottom: 0.5rem; }
.recipe-card p { font-size: 0.95rem; color: var(--color-muted); margin-bottom: 0.75rem; }
.recipe-meta { display: flex; justify-content: space-between; font-size: 0.85rem; color: var(--color-muted); }
.recipe-meta .stars { color: var(--color-star); }

/* === Breadcrumb === */
.breadcrumb { font-size: 0.9rem; color: var(--color-muted); margin-bottom: 1rem; }
.breadcrumb a { color: var(--color-primary); }

/* === Recipe detail === */
.recipe-detail h1 { font-size: 2rem; margin-bottom: 0.5rem; }
.recipe-description { font-size: 1.1rem; color: var(--color-muted); margin-bottom: 1.5rem; }
.recipe-section { margin-top: 2rem; }
.recipe-section h2 { margin-bottom: 0.75rem; border-bottom: 2px solid var(--color-border); padding-bottom: 0.4rem; }
.ingredients-list { list-style: disc; padding-left: 1.5rem; }
.ingredients-list li { padding: 0.25rem 0; }
.steps-list { padding-left: 1.5rem; }
.steps-list li { padding: 0.4rem 0; }

/* === Star rating widget === */
.star-rating { background: var(--color-card); border: 1px solid var(--color-border); border-radius: var(--radius); padding: 1rem 1.25rem; display: flex; flex-wrap: wrap; align-items: center; gap: 0.75rem; }
.rating-label { font-weight: 500; }
.stars-interactive { display: flex; gap: 0.15rem; }
.star-btn {
    background: none; border: none; cursor: pointer;
    font-size: 1.6rem; color: #ccc; padding: 0 2px;
    transition: transform 0.1s;
}
.star-btn.filled { color: var(--color-star); }
.star-btn:hover { transform: scale(1.2); }
.rating-confirmation { color: var(--color-success); font-size: 0.9rem; }
.rating-average { font-size: 0.85rem; color: var(--color-muted); margin-left: auto; }

/* === Submit form === */
.submit-form { max-width: 600px; }
.form-group { margin-bottom: 1.25rem; }
.form-group label { display: block; font-weight: 600; margin-bottom: 0.4rem; }
.form-group input, .form-group select, .form-group textarea {
    width: 100%; padding: 0.6rem 0.8rem;
    border: 1px solid var(--color-border); border-radius: 6px;
    font-size: 1rem; font-family: inherit;
    background: var(--color-card);
}
.form-group input:focus, .form-group select:focus, .form-group textarea:focus {
    outline: none; border-color: var(--color-primary); box-shadow: 0 0 0 3px rgba(224,93,38,0.15);
}

/* === Buttons === */
.btn {
    display: inline-block; padding: 0.6rem 1.5rem;
    border: none; border-radius: 6px; cursor: pointer;
    font-size: 1rem; font-weight: 600; text-align: center;
    color: white; background: var(--color-primary);
    transition: background 0.2s;
}
.btn:hover { background: var(--color-primary-dark); text-decoration: none; color: white; }
.btn:disabled { opacity: 0.5; cursor: not-allowed; }
.btn-primary { background: var(--color-primary); }

/* === Success message === */
.success-message { background: #e8f5e9; border: 1px solid #a5d6a7; border-radius: var(--radius); padding: 2rem; text-align: center; }
.success-message h2 { margin-bottom: 0.5rem; }
.success-message p { margin-bottom: 1rem; }

/* === Validation === */
.valid.modified:not([type=checkbox]) { outline: 1px solid #26b050; }
.invalid { outline: 1px solid #e50000; }
.validation-message { color: #e50000; }

/* === Blazor error UI === */
#blazor-error-ui { background: #ffebee; padding: 0.5rem 1rem; position: fixed; bottom: 0; width: 100%; z-index: 1000; display: none; }
#blazor-error-ui .dismiss { cursor: pointer; float: right; }

